contentBody:
Karan is studying the following code:

```python
class BankAccount:
    def __init__(self):
        self.balance = 5000

    def __deduct(self, amount):
        self.balance -= amount

    def withdraw(self, amount):
        if self.balance >= amount:
            self.__deduct(amount)
            print(f"Remaining balance: {self.balance}")
        else:
            print("Insufficient funds")

acc = BankAccount()
acc.__deduct(200)
```

What will happen when `acc.__deduct(200)` is called on the last line?

option.1:
```python
class InsufficientFundsError:
    def __init__(self, message, balance):
        self.message = message
        self.balance = balance
```

option.2:
```python
class InsufficientFundsError(Exception):
    def __init__(self, message, balance):
        super().__init__(message)
        self.balance = balance
```

option.3:
```python
class InsufficientFundsError(Exception):
    def __init__(self, message, balance):
        self.message = message
        self.balance = balance
```

contentBody:
Sameer runs the following code:

```python
class AgeError(Exception):
    def __init__(self, message, age):
        super().__init__(f"{message}: {age}")
        self.age = age

def verify_age(age):
    if age < 0:
        raise AgeError("Negative age not allowed", age)
    elif age > 120:
        raise AgeError("Age exceeds maximum limit", age)
    return "Valid age"

try:
    result = verify_age(-5)
    print(result)
except AgeError as e:
    print("Caught:", e)
    print("Age value:", e.age)
except ValueError:
    print("Not a number")
finally:
    print("Done")
```

Which of the following statements are **correct**? *(Select all that apply.)*

answerExplanation:
```python
# --- Custom Exceptions ---

class BookNotAvailableError(Exception):
    def __init__(self, message, title):
        super().__init__(message)
        self.title = title


class InvalidReturnError(Exception):
    def __init__(self, message, title):
        super().__init__(message)
        self.title = title


# --- Book Class ---

class Book:
    def __init__(self, title, total_copies):
        self.__title = title
        self.__total_copies = total_copies
        self.__available_copies = total_copies   # All copies start as available

    # Getters
    def get_title(self):
        return self.__title

    def get_available_copies(self):
        return self.__available_copies

    def get_total_copies(self):
        return self.__total_copies

    # Setter with validation
    def set_total_copies(self, n):
        if n > 0:
            self.__total_copies = n
        else:
            print("Invalid: copies must be greater than 0")

    def borrow(self):
        if self.__available_copies > 0:
            self.__available_copies -= 1
            print(f"Borrowed: {self.__title}. Copies left: {self.__available_copies}")
        else:
            raise BookNotAvailableError(
                f'No copies available for "{self.__title}"',
                self.__title
            )

    def return_book(self):
        if self.__available_copies < self.__total_copies:
            self.__available_copies += 1
            print(f"Returned: {self.__title}. Copies left: {self.__available_copies}")
        else:
            raise InvalidReturnError(
                f'All copies of "{self.__title}" are already returned',
                self.__title
            )


# --- Demo ---

book = Book("Clean Code", 2)

# Two successful borrows
book.borrow()
book.borrow()

# Third borrow — triggers BookNotAvailableError
try:
    book.borrow()
except BookNotAvailableError as e:
    print(f"Error: {e}")
    print(f"Book title from exception: {e.title}")

# Successful return
book.return_book()

# Over-return — triggers InvalidReturnError
book.return_book()   # This brings copies back to 2 (all returned)
try:
    book.return_book()
except InvalidReturnError as e:
    print(f"Error: {e}")
```
